import React from 'react';
import { ExternalLink, Terminal } from 'lucide-react';
import { motion } from 'framer-motion';

const ProjectCard = ({ title, description, tags, link, github, image }) => {
  return (
    <motion.div 
      whileHover={{ y: -8 }}
      className="bg-white dark:bg-gray-800 rounded-[2rem] shadow-lg hover:shadow-2xl border border-gray-100 dark:border-gray-700 overflow-hidden transition-all duration-300 flex flex-col h-full group"
    >
      <div className="relative h-64 overflow-hidden">
        <img 
          src={image} 
          alt={title} 
          className="w-full h-full object-cover transition-transform duration-700 group-hover:scale-110"
        />
        <div className="absolute inset-0 bg-gradient-to-t from-gray-900/90 via-gray-900/20 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300 flex items-end p-8">
          <div className="flex gap-4">
            {link && (
              <a href={link} target="_blank" rel="noopener noreferrer" className="p-3 bg-white text-gray-900 rounded-full hover:bg-indigo-50 hover:scale-110 transition-all shadow-lg">
                <ExternalLink className="w-6 h-6" />
              </a>
            )}
            {github && (
              <a href={github} target="_blank" rel="noopener noreferrer" className="p-3 bg-gray-900 text-white rounded-full hover:bg-gray-800 hover:scale-110 transition-all shadow-lg border border-gray-700">
                <Terminal className="w-6 h-6" />
              </a>
            )}
          </div>
        </div>
      </div>
      <div className="p-8 flex-grow flex flex-col">
        <h3 className="text-2xl font-bold mb-4 text-gray-900 dark:text-white group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors">{title}</h3>
        <p className="text-gray-600 dark:text-gray-300 mb-8 leading-relaxed flex-grow text-lg">
          {description}
        </p>
        <div className="flex flex-wrap gap-2 mt-auto">
          {tags.map((tag, index) => (
            <span key={index} className="px-4 py-2 bg-indigo-50/50 dark:bg-indigo-900/20 text-indigo-700 dark:text-indigo-300 border border-indigo-100 dark:border-indigo-800/30 font-semibold rounded-xl text-sm">
              {tag}
            </span>
          ))}
        </div>
      </div>
    </motion.div>
  );
};

export default ProjectCard;

import React from 'react';
import { motion } from 'framer-motion';
import { Briefcase, Calendar, GraduationCap } from 'lucide-react';

const About = () => {
  const experiences = [
    {
      role: 'Frontend Developer',
      company: 'Tech Solutions Inc.',
      period: '2022 - Present',
      description: 'Developed and maintained the core user interface for a SaaS platform using React and Tailwind CSS. Improved rendering performance by 30% and spearheaded the component library.'
    },
    {
      role: 'Web Developer Intern',
      company: 'Creative Agency',
      period: '2021 - 2022',
      description: 'Collaborated with designers to build responsive landing pages. Implemented content management systems for clients using Node.js and Express.'
    }
  ];

  const education = [
    {
      degree: 'B.S. in Computer Science',
      school: 'University of Technology',
      period: '2017 - 2021',
      description: 'Graduated with honors. Relevant coursework: Data Structures, Web Engineering, Database Systems, Software Architecture.'
    }
  ];

  return (
    <div className="container mx-auto px-4 py-20">
      <motion.div 
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        className="max-w-5xl mx-auto"
      >
        {/* Bio Section */}
        <div className="text-center mb-24">
          <h1 className="text-4xl md:text-5xl font-extrabold mb-8 bg-clip-text text-transparent bg-gradient-to-r from-indigo-500 to-purple-600">
            About Me
          </h1>
          <p className="text-lg md:text-xl text-gray-600 dark:text-gray-300 leading-relaxed max-w-3xl mx-auto">
            I am a passionate software engineer specializing in building exceptional digital experiences. Currently, I'm focused on developing full-stack web applications using the MERN stack. I thrive on solving complex problems and transforming them into simple, elegant, and intuitive designs.
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-16">
          {/* Experience Section */}
          <div>
            <div className="flex items-center gap-4 mb-10">
              <div className="p-3 bg-indigo-100 dark:bg-indigo-900/40 rounded-xl text-indigo-600 dark:text-indigo-400">
                <Briefcase className="w-8 h-8" />
              </div>
              <h2 className="text-3xl font-bold">Experience</h2>
            </div>
            <div className="space-y-10">
              {experiences.map((exp, index) => (
                <div key={index} className="relative pl-8 border-l-2 border-indigo-100 dark:border-indigo-900/50">
                  <div className="absolute -left-[9px] top-1 w-4 h-4 bg-indigo-500 rounded-full border-4 border-white dark:border-gray-900"></div>
                  <h3 className="text-2xl font-bold text-gray-900 dark:text-white leading-none">{exp.role}</h3>
                  <div className="flex flex-wrap items-center gap-2 text-sm text-indigo-600 dark:text-indigo-400 font-medium mb-4 mt-3">
                    <span className="font-bold text-gray-700 dark:text-gray-300 text-base">{exp.company}</span>
                    <span className="hidden sm:inline">&bull;</span>
                    <span className="flex items-center gap-1"><Calendar className="w-4 h-4" /> {exp.period}</span>
                  </div>
                  <p className="text-gray-600 dark:text-gray-400 leading-relaxed text-lg text-justify">
                    {exp.description}
                  </p>
                </div>
              ))}
            </div>
          </div>

          {/* Education Section */}
          <div>
            <div className="flex items-center gap-4 mb-10">
              <div className="p-3 bg-purple-100 dark:bg-purple-900/40 rounded-xl text-purple-600 dark:text-purple-400">
                <GraduationCap className="w-8 h-8" />
              </div>
              <h2 className="text-3xl font-bold">Education</h2>
            </div>
            <div className="space-y-10">
              {education.map((edu, index) => (
                <div key={index} className="relative pl-8 border-l-2 border-purple-100 dark:border-purple-900/50">
                  <div className="absolute -left-[9px] top-1 w-4 h-4 bg-purple-500 rounded-full border-4 border-white dark:border-gray-900"></div>
                  <h3 className="text-2xl font-bold text-gray-900 dark:text-white leading-none">{edu.degree}</h3>
                  <div className="flex items-center gap-2 text-sm text-purple-600 dark:text-purple-400 font-medium mb-4 mt-3">
                    <span className="font-bold text-gray-700 dark:text-gray-300 text-base">{edu.school}</span>
                    <span>&bull;</span>
                    <span className="flex items-center gap-1"><Calendar className="w-4 h-4" /> {edu.period}</span>
                  </div>
                  <p className="text-gray-600 dark:text-gray-400 leading-relaxed text-lg text-justify">
                    {edu.description}
                  </p>
                </div>
              ))}
            </div>
          </div>
        </div>
      </motion.div>
    </div>
  );
};

export default About;

import React from 'react';
import { motion } from 'framer-motion';
import { Database, Layout, Server, FileJson, Code } from 'lucide-react';

const Home = () => {
  const skills = [
    { name: 'React', icon: <Layout className="text-blue-500 w-10 h-10" /> },
    { name: 'Node.js', icon: <Server className="text-green-500 w-10 h-10" /> },
    { name: 'MongoDB', icon: <Database className="text-green-600 w-10 h-10" /> },
    { name: 'Express', icon: <FileJson className="text-gray-600 dark:text-gray-300 w-10 h-10" /> },
    { name: 'Tailwind CSS', icon: <Code className="text-teal-400 w-10 h-10" /> },
  ];

  return (
    <div className="container mx-auto px-4">
      {/* Hero Section */}
      <section className="min-h-[85vh] flex flex-col justify-center items-center text-center">
        <motion.div
          initial={{ opacity: 0, y: 30 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.8 }}
        >
          <span className="text-indigo-600 dark:text-indigo-400 font-bold tracking-widest uppercase text-sm mb-6 block">
            Welcome to my world
          </span>
          <h1 className="text-5xl md:text-7xl font-extrabold mb-8 tracking-tight leading-tight">
            Building Digital <span className="text-transparent bg-clip-text bg-gradient-to-r from-indigo-500 via-purple-500 to-pink-500">Experiences</span>
          </h1>
          <p className="text-lg md:text-xl text-gray-600 dark:text-gray-300 mb-12 max-w-2xl mx-auto leading-relaxed">
            I am a Full Stack Developer specializing in the MERN stack. I transform complex ideas into seamless, scalable, and beautifully designed web applications.
          </p>
          <div className="flex flex-col sm:flex-row gap-4 justify-center">
            <button className="px-8 py-4 bg-indigo-600 hover:bg-indigo-700 text-white rounded-full font-bold transition-all shadow-[0_0_20px_rgba(79,70,229,0.4)] hover:shadow-[0_0_30px_rgba(79,70,229,0.6)] hover:-translate-y-1">
              View My Work
            </button>
            <button className="px-8 py-4 bg-white dark:bg-gray-800 text-gray-900 dark:text-white border-2 border-gray-200 dark:border-gray-700 rounded-full font-bold hover:bg-gray-50 dark:hover:bg-gray-700 transition-all hover:-translate-y-1">
              Contact Me
            </button>
          </div>
        </motion.div>
      </section>

      {/* Skills Section */}
      <section className="py-20 border-t border-gray-100 dark:border-gray-800">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold mb-4">Tech Stack</h2>
          <p className="text-lg text-gray-500 dark:text-gray-400">The tools I use to bring ideas to life</p>
        </div>

        <div className="flex flex-wrap justify-center gap-8 md:gap-16">
          {skills.map((skill, index) => (
            <motion.div 
              key={index}
              className="flex flex-col items-center gap-5 group"
              whileHover={{ scale: 1.1 }}
              initial={{ opacity: 0, y: 20 }}
              whileInView={{ opacity: 1, y: 0 }}
              viewport={{ once: true }}
              transition={{ delay: index * 0.1 }}
            >
              <div className="p-6 bg-white dark:bg-gray-800 rounded-2xl shadow-sm border border-gray-100 dark:border-gray-700 group-hover:shadow-lg transition-all group-hover:border-indigo-100 dark:group-hover:border-indigo-900/50">
                {skill.icon}
              </div>
              <span className="font-semibold text-gray-800 dark:text-gray-200">{skill.name}</span>
            </motion.div>
          ))}
        </div>
      </section>

      {/* CTA Section */}
      <section className="py-20 mb-10">
        <div className="bg-gradient-to-br from-indigo-900 to-purple-900 rounded-[3rem] p-10 md:p-16 text-center text-white relative overflow-hidden shadow-2xl">
          <div className="absolute top-0 right-0 -mt-20 -mr-20 w-64 h-64 bg-white opacity-5 rounded-full blur-3xl"></div>
          <div className="absolute bottom-0 left-0 -mb-20 -ml-20 w-80 h-80 bg-indigo-500 opacity-30 rounded-full blur-3xl"></div>

          <h2 className="text-3xl md:text-5xl font-bold mb-6 relative z-10 leading-tight">Let's build something <br/> amazing together.</h2>
          <p className="text-indigo-200 mb-10 max-w-2xl mx-auto text-lg relative z-10">
            Whether you have a project in mind or just want to chat about technology, my inbox is always open.
          </p>
          <button className="px-10 py-4 bg-white text-indigo-900 rounded-full font-bold hover:bg-indigo-50 transition-colors shadow-lg relative z-10 text-lg">
            Start a Conversation
          </button>
        </div>
      </section>
    </div>
  );
};

export default Home;

import React from 'react';
import { motion } from 'framer-motion';
import ProjectCard from '../components/ProjectCard';

const dummyProjects = [
  {
    id: 1,
    title: 'E-Commerce Platform',
    description: 'A full-featured e-commerce platform built with the MERN stack. Features include user authentication, product management, shopping cart, and Stripe payment integration for seamless checkout.',
    tags: ['MongoDB', 'Express', 'React', 'Node.js', 'Stripe'],
    link: '#',
    github: '#',
    image: 'https://images.unsplash.com/photo-1557821552-17105153ce67?q=80&w=1000&auto=format&fit=crop'
  },
  {
    id: 2,
    title: 'Real-time Chat App',
    description: 'A robust message application utilizing Socket.io for instant communication. Includes private messaging, group chats, dynamic typing indicators, and reliable online status detection.',
    tags: ['React', 'Socket.io', 'Node.js', 'Tailwind'],
    link: '#',
    github: '#',
    image: 'https://images.unsplash.com/photo-1611162617474-5b21e879e113?q=80&w=1000&auto=format&fit=crop'
  },
  {
    id: 3,
    title: 'Task Management Dashboard',
    description: 'A Kanban-style task management board allowing teams to intuitively organize workflows, assign tasks, and track their daily progress using beautiful drag-and-drop functionality.',
    tags: ['React', 'Redux', 'MongoDB', 'Framer'],
    link: '#',
    github: '#',
    image: 'https://images.unsplash.com/photo-1517245386807-bb43f82c33c4?q=80&w=1000&auto=format&fit=crop'
  }
];

const Projects = () => {
  return (
    <div className="container mx-auto px-4 py-20 pb-32">
      <motion.div 
        initial={{ opacity: 0, y: 30 }}
        animate={{ opacity: 1, y: 0 }}
        className="text-center mb-20"
      >
        <h1 className="text-4xl md:text-5xl font-extrabold mb-8 bg-clip-text text-transparent bg-gradient-to-r from-indigo-500 to-purple-600">
          Selected Works
        </h1>
        <p className="text-xl text-gray-600 dark:text-gray-300 max-w-3xl mx-auto leading-relaxed">
          Here are some of the projects I've worked on recently. They demonstrate my ability to build dynamic, scalable, and beautifully designed full-stack web applications.
        </p>
      </motion.div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-12 max-w-7xl mx-auto">
        {dummyProjects.map((project, index) => (
          <motion.div
            key={project.id}
            initial={{ opacity: 0, y: 40 }}
            animate={{ opacity: 1, y: 0 }}
            transition={{ delay: index * 0.15 + 0.2, duration: 0.5 }}
          >
            <ProjectCard 
              title={project.title}
              description={project.description}
              tags={project.tags}
              link={project.link}
              github={project.github}
              image={project.image}
            />
          </motion.div>
        ))}
      </div>
    </div>
  );
};

export default Projects;
